      {editingIconBlock && (
        <div className="fixed inset-0 z-[400] flex items-center justify-center p-6 bg-black/95 backdrop-blur-2xl animate-in fade-in" onClick={() => setEditingIconBlock(null)}>
           <div className="w-full max-w-2xl bg-zinc-900 border border-white/10 rounded-[40px] p-10 space-y-8 shadow-2xl animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <div className="flex items-center justify-between">
                 <div className="space-y-1">
                   <h2 className="text-xl font-black text-white uppercase italic tracking-tighter">Escolher Ícone</h2>
                   <p className="text-[10px] font-black uppercase text-zinc-500 tracking-[0.2em]">Biblioteca de símbolos ou cole PNG via CTRL+V</p>
                 </div>
                 <button onClick={() => setEditingIconBlock(null)} className="p-3 hover:bg-white/5 rounded-full text-zinc-500"><X size={24}/></button>
              </div>
              <div className="p-6 border-2 border-dashed border-brand/20 bg-brand/5 rounded-[24px] flex flex-col items-center justify-center gap-2 group hover:border-brand/50 transition-all"><ClipboardPaste size={32} className="text-brand opacity-60 group-hover:opacity-100" /><p className="text-[10px] font-black uppercase text-brand/80 tracking-widest">Dica: Cole um PNG/JPG diretamente aqui (CTRL+V)</p></div>
              <div className="grid grid-cols-4 sm:grid-cols-6 gap-4 p-1">
                 {ICON_LIBRARY_PRESETS.map(item => (
                    <button key={item.id} onClick={() => { updateSlideProperties([{ path: ['blocks', editingIconBlock.index, 'options', 'icon'], value: item.id }, { path: ['blocks', editingIconBlock.index, 'options', 'customIcon'], value: undefined }]); setEditingIconBlock(null); }} className={`flex flex-col items-center justify-center gap-3 p-5 rounded-3xl border-2 transition-all group ${editingIconBlock.block.options?.icon === item.id ? 'border-brand bg-brand/10 text-brand' : 'border-white/5 bg-black/40 hover:border-brand/50'}`}><item.icon size={32} strokeWidth={1.5} className="transition-transform group-hover:scale-110" /><span className="text-[8px] font-black uppercase tracking-tighter text-zinc-600 group-hover:text-brand">{item.label}</span></button>
                 ))}
              </div>
              <div className="space-y-3">
                 <label className="text-[9px] font-black uppercase text-zinc-500 px-1 tracking-widest">Personalizado (Lucide Name, URL ou SVG)</label>
                 <div className="flex gap-3"><input type="text" placeholder="Ex: Rocket, https://..., <svg..." className="flex-1 bg-black/40 border border-white/5 rounded-2xl py-4 px-5 text-sm font-bold text-white outline-none focus:border-brand/50 transition-all" value={iconInput} onChange={(e) => setIconInput(e.target.value)} /><button onClick={() => { updateSlideProperties([{ path: ['blocks', editingIconBlock.index, 'options', 'customIcon'], value: iconInput }, { path: ['blocks', editingIconBlock.index, 'options', 'icon'], value: undefined }]); setEditingIconBlock(null); }} className="px-8 py-4 bg-zinc-800 text-white font-black uppercase text-[10px] rounded-2xl hover:bg-zinc-700 transition-all">Aplicar</button></div>
              </div>
           </div>
        </div>
