              <div className="flex items-center justify-between">
                 <div className="space-y-1">
                   <h2 className="text-xl font-black text-white uppercase italic tracking-tighter">{editingPaletteId ? 'Editar Identidade' : 'Nova Identidade Visual'}</h2>
                   <p className="text-[10px] font-black uppercase text-zinc-500 tracking-[0.2em]">Defina as cores e fontes da marca</p>
                 </div>
                 <button onClick={() => { setIsCreatingPalette(false); setEditingPaletteId(null); }} className="p-3 hover:bg-white/5 rounded-full text-zinc-500"><X size={24}/></button>
              </div>
              <div className="space-y-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-zinc-500 px-1 tracking-widest">Nome da Marca</label>
                  <input type="text" value={newPaletteData.name} onChange={(e) => setNewPaletteData({ ...newPaletteData, name: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-2xl py-4 px-6 text-base text-white font-bold outline-none focus:border-brand/50 transition-all" placeholder="Ex: Apple Minimal" />
